import torch
import torch.nn as nn
import math
from torch.utils.cpp_extension import load_inline

# Define the fused CUDA kernel with optimized memory access
fused_kernel_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <math.h>

template<typename T>
__device__ __forceinline__ T gelu_approx(T x) {
    // Fast GELU approximation: 0.5x * (1 + tanh(sqrt(2/π) * (x + 0.044715 * x^3)))
    const float kAlpha = 0.7978845608028654f;
    const float kBeta = 0.044715f;
    float x3 = x * x * x;
    float inner = kAlpha * (x + kBeta * x3);
    return x * 0.5f * (1.0f + tanhf(inner));
}

template<typename T>
__device__ __forceinline__ T hardtanh_clamp(T x, T min_val, T max_val) {
    return fminf(fmaxf(x, min_val), max_val);
}

__global__ void fused_gemm_activation_kernel(
    const float* __restrict__ input,
    const float* __restrict__ weight,
    const float* __restrict__ bias,
    float* __restrict__ output,
    const float scaling_factor,
    const float hardtanh_min,
    const float hardtanh_max,
    const int batch_size,
    const int in_features,
    const int out_features
) {
    // Use 2D block for better memory coalescing
    const int TILE_SIZE = 32;
    __shared__ float input_tile[TILE_SIZE][TILE_SIZE + 1];  // +1 for bank conflict avoidance
    __shared__ float weight_tile[TILE_SIZE][TILE_SIZE + 1];

    int tx = threadIdx.x;
    int ty = threadIdx.y;

    int block_row = blockIdx.y * TILE_SIZE;
    int block_col = blockIdx.x * TILE_SIZE;

    int row = block_row + ty;
    int col = block_col + tx;

    float sum = 0.0f;

    // Precompute loop bounds
    int num_tiles = (in_features + TILE_SIZE - 1) / TILE_SIZE;

    for (int tile = 0; tile < num_tiles; ++tile) {
        int tile_offset = tile * TILE_SIZE;

        // Load input tile with coalesced access
        int input_idx = row * in_features + tile_offset + tx;
        if (row < batch_size && (tile_offset + tx) < in_features) {
            input_tile[ty][tx] = input[input_idx];
        } else {
            input_tile[ty][tx] = 0.0f;
        }

        // Load weight tile with transposed access pattern
        int weight_idx = col * in_features + tile_offset + ty;
        if (col < out_features && (tile_offset + ty) < in_features) {
            weight_tile[ty][tx] = weight[weight_idx];
        } else {
            weight_tile[ty][tx] = 0.0f;
        }

        __syncthreads();

        // Unrolled matrix multiplication
        #pragma unroll
        for (int k = 0; k < TILE_SIZE; ++k) {
            sum += input_tile[ty][k] * weight_tile[k][tx];
        }

        __syncthreads();
    }

    // Write result with fused activations
    if (row < batch_size && col < out_features) {
        // Add bias if present
        if (bias != nullptr) {
            sum += bias[col];
        }

        // Apply scaling
        sum *= scaling_factor;

        // Apply hardtanh
        sum = hardtanh_clamp(sum, hardtanh_min, hardtanh_max);

        // Apply GELU
        sum = gelu_approx(sum);

        output[row * out_features + col] = sum;
    }
}

torch::Tensor fused_gemm_activation_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    float scaling_factor,
    float hardtanh_min,
    float hardtanh_max
) {
    int batch_size = input.size(0);
    int in_features = input.size(1);
    int out_features = weight.size(0);

    auto output = torch::empty({batch_size, out_features}, 
                               torch::device(input.device()).dtype(input.dtype()));

    // Use tiled kernel
    const int TILE_SIZE = 32;
    dim3 block_dim(TILE_SIZE, TILE_SIZE);
    dim3 grid_dim(
        (out_features + TILE_SIZE - 1) / TILE_SIZE,
        (batch_size + TILE_SIZE - 1) / TILE_SIZE
    );

    fused_gemm_activation_kernel<<<grid_dim, block_dim>>>(
        input.data_ptr<float>(),
        weight.data_ptr<float>(),
        bias.defined() ? bias.data_ptr<float>() : nullptr,
        output.data_ptr<float>(),
        scaling_factor,
        hardtanh_min,
        hardtanh_max,
        batch_size,
        in_features,
        out_features
    );

    return output;
}
"""

fused_kernel_cpp_source = """
torch::Tensor fused_gemm_activation_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    float scaling_factor,
    float hardtanh_min,
    float hardtanh_max
);
"""

# Compile the inline CUDA code with optimization flags
fused_gemm_activation = load_inline(
    name="fused_gemm_activation",
    cpp_sources=fused_kernel_cpp_source,
    cuda_sources=fused_kernel_source,
    functions=["fused_gemm_activation_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=[""],
)

class ModelNew(nn.Module):
    """
    Optimized model with fused GEMM + activation CUDA kernel.
    """
    def __init__(self, in_features, out_features, scaling_factor, hardtanh_min, hardtanh_max):
        super(ModelNew, self).__init__()
        self.in_features = in_features
        self.out_features = out_features
        self.scaling_factor = scaling_factor
        self.hardtanh_min = hardtanh_min
        self.hardtanh_max = hardtanh_max

        # Initialize weight and bias parameters
        self.weight = nn.Parameter(torch.empty(out_features, in_features))
        self.bias = nn.Parameter(torch.empty(out_features))

        # Initialize parameters
        nn.init.kaiming_uniform_(self.weight, a=math.sqrt(5))
        if self.bias is not None:
            fan_in, _ = nn.init._calculate_fan_in_and_fan_out(self.weight)
            bound = 1 / math.sqrt(fan_in) if fan_in > 0 else 0
            nn.init.uniform_(self.bias, -bound, bound)

        # Register the fused kernel
        self.fused_kernel = fused_gemm_activation

    def forward(self, x):
        # Use the fused kernel for all operations
        return self.fused_kernel.fused_gemm_activation_cuda(
            x,
            self.weight,
            self.bias,
            self.scaling_factor,
            self.hardtanh_min,
            self.hardtanh_max
        )

